lesson.codeExample:
h1 {
  color: #0284c7;  /* Bleu Mediterranean */
}

p {
  color: #64748b;  /* Gris secondaire */
}

body {
  background-color: #f8fafc;
}

body {
  font-family: 'Inter', 'Helvetica', sans-serif;
}

h1 {
  margin-bottom: 40px;
}

/* Centrer horizontalement un élément en bloc */
.container {
  margin: 0 auto;  /* Haut/bas: 0, Gauche/droite: auto */
}

.card {
  border: 2px solid #0284c7;
  /* Ou cibler un seul côté */
  border-left: 4px solid #059669;  /* Vert */
}

button {
  border-radius: 8px;    /* Léger arrondi */
}

.pill {
  border-radius: 9999px; /* Forme de pilule */
}

.avatar {
  border-radius: 50%;    /* Cercle parfait */
}

.centrage-parfait {
  display: flex;
  justify-content: center;  /* Horizontal */
  align-items: center;       /* Vertical */
  height: 100vh;
}

body {
  /* Dégradé sombre finance */
  background: linear-gradient(135deg, #0f172a, #1e293b);

  /* Dégradé bleu/violet */
  background: linear-gradient(to right, #0284c7, #7c3aed);
}

.glass-card {
  background: rgba(255, 255, 255, 0.1);
  backdrop-filter: blur(10px);
  border: 1px solid rgba(255, 255, 255, 0.2);
  border-radius: 20px;
  padding: 40px;
}

// Changer le texte d'un élément
